import{_ as s,o as e,c as t,ag as n}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"本地配置文件","description":"","frontmatter":{},"headers":[],"relativePath":"zh/settings/local-file-config.md","filePath":"zh/settings/local-file-config.md","lastUpdated":1782688753000}'),i={name:"zh/settings/local-file-config.md"};function p(o,a,l,c,d,r){return e(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="本地配置文件" tabindex="-1">本地配置文件 <a class="header-anchor" href="#本地配置文件" aria-label="Permalink to &quot;本地配置文件&quot;">​</a></h1><p>EasyYapi 使用 <code>.easy.api.config</code> 文件作为本地配置文件。从 EasyYapi 3.0 起推荐使用 <a href="./rule-authoring#基于文件夹的规则文件"><code>.easyapi/</code> 文件夹模型</a>，<code>.easyapi/</code> 中的每个常规文件都会被自动加载。下方旧的 <code>.easy.api.config*</code> 文件仍会被读取以保持向后兼容。</p><h2 id="文件位置" tabindex="-1">文件位置 <a class="header-anchor" href="#文件位置" aria-label="Permalink to &quot;文件位置&quot;">​</a></h2><p>规则文件基于 <strong>IntelliJ 工程根目录</strong>（你在 IDE 中打开的文件夹，即 <code>project.basePath</code>）解析。发现过程<strong>不会</strong>向下递归到子目录，因此当父目录被 作为工程打开时，放在嵌套模块文件夹中的配置文件<strong>不会</strong>被加载。</p><blockquote><p><strong>多模块工程注意：</strong> 不存在按模块划分的配置层。若你将 <code>your-project/</code> 作为工程 打开，只会读取 <code>your-project/</code> 及其<strong>祖先</strong>目录下的 <code>.easy.api.config</code> / <code>.easyapi/</code>。若希望某个模块拥有独立规则，请将该模块文件夹单独作为 IntelliJ 工程打开，或将所有规则统一放在共享的 <code>&lt;project&gt;/.easyapi/</code> 文件夹中。</p></blockquote><h3 id="项目根目录" tabindex="-1">项目根目录 <a class="header-anchor" href="#项目根目录" aria-label="Permalink to &quot;项目根目录&quot;">​</a></h3><p>你在 IDE 中打开的文件夹：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>your-project/</span></span>
<span class="line"><span>├── .easy.api.config</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>└── pom.xml</span></span></code></pre></div><p>旧版的 <code>.easy.api.config[.properties|.yml|.yaml]</code> 文件还会从工程根目录<strong>向上</strong> 查找祖先目录（例如多个工程共享的父目录中的配置）。</p><h3 id="_3-0-文件夹模型-推荐" tabindex="-1">3.0+ 文件夹模型（推荐） <a class="header-anchor" href="#_3-0-文件夹模型-推荐" aria-label="Permalink to &quot;3.0+ 文件夹模型（推荐）&quot;">​</a></h3><p>在 <code>.easyapi/</code> 文件夹中放置任意数量的 <code>.rules</code>（或 <code>.properties</code>）文件。每个常规文件都会被加载——无需维护文件列表。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>your-project/</span></span>
<span class="line"><span>├── .easyapi/</span></span>
<span class="line"><span>│   ├── naming.rules</span></span>
<span class="line"><span>│   ├── security.rules</span></span>
<span class="line"><span>│   └── postman.rules</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>└── pom.xml</span></span></code></pre></div><p>全局范围同样适用此模型：<code>~/.easyapi/*.rules</code> 会为本机所有项目加载。可在 <strong>Settings → EasyApi → Rules</strong>（Project / Global / Remote 子标签页）中以可视化方式管理文件。</p><h2 id="文件格式" tabindex="-1">文件格式 <a class="header-anchor" href="#文件格式" aria-label="Permalink to &quot;文件格式&quot;">​</a></h2><p>配置文件使用 <code>key=value</code> 格式：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 注释以 # 开头</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># API 名称规则</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">api.name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#name</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 字段忽略规则</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">field.ignore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.hasAnn(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.fasterxml.jackson.annotation.JsonIgnore&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 类型转换</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">json.rule.convert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.type().name()==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;java.util.Date&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> =&gt; java.lang.String</span></span></code></pre></div><h2 id="配置合并" tabindex="-1">配置合并 <a class="header-anchor" href="#配置合并" aria-label="Permalink to &quot;配置合并&quot;">​</a></h2><p>配置由多个来源按优先级合并。在同一来源内，<code>.easyapi/</code> 中的文件按文件名排序依次 读取并追加。对于同一个 key，高优先级来源会覆盖低优先级来源。</p><table tabindex="0"><thead><tr><th style="text-align:center;">优先级</th><th>来源</th><th>加载位置</th></tr></thead><tbody><tr><td style="text-align:center;">4</td><td><strong>工程规则</strong></td><td><code>&lt;project&gt;/.easyapi/*</code>（全部常规文件）+ 从 <code>&lt;project&gt;</code> 向上查找的旧版 <code>.easy.api.config*</code></td></tr><tr><td style="text-align:center;">3</td><td>扩展规则</td><td>内置框架预设（Spring、Jackson、Validation、Swagger……），可在 Settings → Extensions 中开关</td></tr><tr><td style="text-align:center;">3</td><td>远程规则</td><td>来自 <code>remote.url</code> 的 URL（Settings → Rules → Remote）</td></tr><tr><td style="text-align:center;">2</td><td>全局规则</td><td><code>~/.easyapi/*</code>（全部常规文件）</td></tr></tbody></table><p>工程规则优先级最高，全局规则为最低的兜底层。不存在单独的“模块级”配置层。</p>`,20)])])}const k=s(i,[["render",p]]);export{g as __pageData,k as default};
